const { execFileSync } = require('child_process');
const fs = require('fs');
const git = '/usr/bin/git';
const repo = '/data/repo';
const gitOpts = { cwd: repo, env: { HOME: '/root', PATH: '/usr/local/bin:/usr/bin:/bin' } };

try {
  // Read local version
  let localData = { version: '0.0.0', changelog: [], date: '' };
  try { localData = JSON.parse(fs.readFileSync('/data/scenarios/version.json', 'utf8')); } catch(e) {}

  // Fetch remote
  try { execFileSync(git, ['fetch', 'origin', 'main', '--quiet'], { ...gitOpts, timeout: 15000 }); } catch(e) {}

  const localHash = execFileSync(git, ['rev-parse', 'HEAD'], gitOpts).toString().trim();
  let remoteHash = localHash;
  try { remoteHash = execFileSync(git, ['rev-parse', 'origin/main'], gitOpts).toString().trim(); } catch(e) {}

  let remoteData = { version: localData.version, changelog: localData.changelog, date: localData.date };
  try {
    const raw = execFileSync(git, ['show', 'origin/main:nginx/html/version.json'], gitOpts).toString();
    remoteData = JSON.parse(raw);
  } catch(e) {}

  const updateAvailable = localHash !== remoteHash;
  const rollbackAvailable = fs.existsSync(repo + '/.update-rollback-hash');

  return [{ json: {
    localVersion: localData.version,
    remoteVersion: remoteData.version,
    remoteDate: remoteData.date || '',
    updateAvailable: updateAvailable,
    localHash: localHash.slice(0, 8),
    remoteHash: remoteHash.slice(0, 8),
    changelog: remoteData.changelog || [],
    rollbackAvailable: rollbackAvailable
  }}];
} catch(e) {
  return [{ json: { error: e.message, status: 'error' } }];
}

const { execFileSync } = require('child_process');
const fs = require('fs');
const git = '/usr/bin/git';
const repo = '/data/repo';
const gitOpts = { cwd: repo, env: { HOME: '/root', PATH: '/usr/local/bin:/usr/bin:/bin' }, timeout: 120000 };

try {
  // Save rollback point
  const currentHash = execFileSync(git, ['rev-parse', 'HEAD'], gitOpts).toString().trim();
  fs.writeFileSync(repo + '/.update-rollback-hash', currentHash, 'utf8');
  try {
    const ver = fs.readFileSync(repo + '/nginx/html/version.json', 'utf8');
    fs.writeFileSync(repo + '/.update-rollback-version.json', ver, 'utf8');
  } catch(e) {}

  // Pull
  const pullOut = execFileSync(git, ['pull', 'origin', 'main', '--ff-only'], gitOpts).toString();

  // Clear update cache signal
  return [{ json: { status: 'ok', message: 'Update applied successfully', detail: pullOut.trim() } }];
} catch(e) {
  return [{ json: { error: e.message, status: 'error' } }];
}

const { execFileSync } = require('child_process');
const fs = require('fs');
const git = '/usr/bin/git';
const repo = '/data/repo';
const gitOpts = { cwd: repo, env: { HOME: '/root', PATH: '/usr/local/bin:/usr/bin:/bin' }, timeout: 60000 };

try {
  const rollbackFile = repo + '/.update-rollback-hash';
  if (!fs.existsSync(rollbackFile)) {
    return [{ json: { status: 'error', message: 'No rollback point available' } }];
  }
  const rollbackHash = fs.readFileSync(rollbackFile, 'utf8').trim();
  execFileSync(git, ['checkout', rollbackHash, '--', '.'], gitOpts);
  fs.unlinkSync(rollbackFile);
  try { fs.unlinkSync(repo + '/.update-rollback-version.json'); } catch(e) {}
  return [{ json: { status: 'ok', message: 'Rolled back successfully' } }];
} catch(e) {
  return [{ json: { error: e.message, status: 'error' } }];
}
